import React, { useEffect, useState } from 'react';
import { fetchLessons } from '../services/sheetsService';
import { Lesson, SubjectColor } from '../types';

const Agenda: React.FC = () => {
  const [lessons, setLessons] = useState<Lesson[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      const data = await fetchLessons();
      setLessons(data);
      setLoading(false);
    };
    loadData();
  }, []);

  const getBadgeStyles = (subject: string) => {
    const s = subject.toLowerCase();
    if (s.includes('météo')) return SubjectColor.METEO;
    if (s.includes('aéro')) return SubjectColor.AERO;
    if (s.includes('connaissance')) return SubjectColor.CONNAISSANCE;
    if (s.includes('nav')) return SubjectColor.NAVIGATION;
    if (s.includes('histoire')) return SubjectColor.HISTOIRE;
    return SubjectColor.DEFAULT;
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] space-y-4">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        <p className="text-slate-500 animate-pulse">Décollage des données en cours...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Prochains Cours</h2>
        <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-sm font-semibold">
          Session 2024
        </span>
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
        {lessons.length > 0 ? (
          lessons.map((lesson) => (
            <div 
              key={lesson.id} 
              className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow"
            >
              <div className="p-5">
                <div className="flex justify-between items-start mb-4">
                  <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold border ${getBadgeStyles(lesson.subject)}`}>
                    {lesson.subject}
                  </span>
                  <div className="text-slate-400 text-sm">
                    <i className="fa-regular fa-clock mr-1"></i> {lesson.time}
                  </div>
                </div>

                <h3 className="text-lg font-bold text-slate-900 mb-2">{lesson.description || lesson.subject}</h3>

                <div className="space-y-2 mt-4 text-sm text-slate-600">
                  <div className="flex items-center">
                    <i className="fa-solid fa-calendar-day w-5 text-blue-500"></i>
                    <span>{new Date(lesson.date).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
                  </div>
                  <div className="flex items-center">
                    <i className="fa-solid fa-location-dot w-5 text-red-400"></i>
                    <span>{lesson.location}</span>
                  </div>
                  <div className="flex items-center">
                    <i className="fa-solid fa-user-tie w-5 text-slate-400"></i>
                    <span>M. {lesson.instructor}</span>
                  </div>
                </div>
              </div>
              <div className="px-5 py-3 bg-slate-50 border-t border-slate-100 flex justify-end">
                <button className="text-blue-600 font-medium text-sm hover:underline">
                  Voir documents <i className="fa-solid fa-arrow-right ml-1"></i>
