import { Lesson } from '../types';

/**
 * URL d'export CSV pour le Google Sheet partagé.
 * Note: Le document doit être partagé en "Lecteur" pour toute personne disposant du lien.
 */
const SHEET_ID = '1r4UEhDB27-5F23UbGx_SreFTODg114vQQOzjjm29Yjg';
const GID = '986104196';
const GOOGLE_SHEET_CSV_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/export?format=csv&gid=${GID}`;

export const fetchLessons = async (): Promise<Lesson[]> => {
  try {
    const response = await fetch(GOOGLE_SHEET_CSV_URL);
    if (!response.ok) throw new Error('Erreur lors du téléchargement du fichier Sheets');

    const csvText = await response.text();
    const rows = csvText.split(/\r?\n/).map(row => {
      // Simple CSV parser handling quotes
      const matches = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g);
      return matches ? matches.map(m => m.replace(/^"|"$/g, '')) : [];
    });

    // On ignore les en-têtes (on suppose la ligne 0 est l'en-tête)
    // On mappe les colonnes selon une structure probable : Date, Heure, Matière, Intervenant, Lieu
    // Si la structure diffère, on s'adapte ou on utilise des index par défaut.
    const lessons: Lesson[] = rows.slice(1)
      .filter(row => row.length >= 3 && row[0] !== "") // Filtrer les lignes vides
      .map((row, index) => ({
        id: String(index),
        date: row[0] || 'Date inconnue',
        time: row[1] || 'Non spécifié',
        subject: row[2] || 'Cours BIA',
        instructor: row[3] || 'TBD',
        location: row[4] || 'Salle de cours',
        description: row[5] || ''
      }));

    return lessons;
  } catch (error) {
    console.error("Erreur Sheets Service:", error);
    // Retourne un tableau vide en cas d'erreur pour que le composant gère l'état vide
    return [];
  }
};

