import React, { useState, useEffect } from 'react';

interface Article {
  id: string;
  title: string;
  published: string;
  updated: string;
  summary: string;
  link: string;
  author: string;
  thumbnail?: string;
}

const Actus: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    const fetchBloggerFeed = async () => {
      try {
        // Flux JSON public de Blogger
        const response = await fetch('https://bia-acp.blogspot.com/feeds/posts/default?alt=json');
        if (!response.ok) throw new Error('Failed to fetch');

        const data = await response.json();
        const entries = data.feed.entry || [];

        const parsedArticles: Article[] = entries.map((entry: any) => {
          const alternateLink = entry.link.find((l: any) => l.rel === 'alternate');
          const content = entry.content ? entry.content.$t : (entry.summary ? entry.summary.$t : '');

          // Extraction simple d'une image si présente
          const imgMatch = content.match(/<img[^>]+src="([^">]+)"/);
          const thumbnail = imgMatch ? imgMatch[1] : null;

          return {
            id: entry.id.$t,
            title: entry.title.$t,
            published: new Date(entry.published.$t).toLocaleDateString('fr-FR', {
              day: 'numeric',
              month: 'long',
              year: 'numeric'
            }),
            updated: entry.updated.$t,
            summary: content.replace(/<[^>]*>?/gm, '').substring(0, 150) + '...', // Strip HTML for summary
            link: alternateLink ? alternateLink.href : '#',
            author: entry.author[0].name.$t,
            thumbnail: thumbnail
          };
        });

        setArticles(parsedArticles);
        setLoading(false);
      } catch (err) {
        console.error("Erreur lors de la récupération du blog:", err);
        setError(true);
        setLoading(false);
      }
    };

    fetchBloggerFeed();
  }, []);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] animate-pulse">
        <div className="w-16 h-16 bg-slate-200 rounded-full flex items-center justify-center mb-4">
          <i className="fa-solid fa-spinner fa-spin text-slate-400 text-2xl"></i>
        </div>
        <p className="text-slate-400 font-medium">Chargement des dernières nouvelles...</p>
      </div>
    );
  }

  if (error || articles.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-3xl border border-slate-200 p-8 text-center">
        <div className="w-20 h-20 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-3xl mb-6">
          <i className="fa-solid fa-rss"></i>
        </div>
        <h3 className="text-xl font-bold text-slate-800 mb-2">Impossible de charger les articles</h3>
        <p className="text-slate-500 max-w-sm mb-8 leading-relaxed">
          Nous n'avons pas pu récupérer les articles du blog automatiquement. Vous pouvez les consulter directement sur le site officiel.
        </p>
        <a 
          href="https://bia-acp.blogspot.com/" 
          target="_blank" 
          rel="noopener noreferrer"
          className="px-8 py-3 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
        >
          Visiter le blog BIA-ACP
        </a>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header Statistique / Rapide */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
        <div className="flex items-center">
          <div className="w-10 h-10 bg-orange-50 text-orange-600 rounded-xl flex items-center justify-center mr-4">
            <i className="fa-solid fa-fire text-lg"></i>
          </div>
          <div>
            <h4 className="font-bold text-slate-800 text-sm">Blog BIA-ACP</h4>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Fil d'actualité en direct</p>
          </div>
        </div>
        <a 
          href="https://bia-acp.blogspot.com/" 
          target="_blank" 
          rel="noopener noreferrer"
          className="text-xs font-bold text-blue-600 hover:text-blue-700 flex items-center"
        >
          Voir tout sur Blogger
          <i className="fa-solid fa-arrow-right ml-2"></i>
        </a>
      </div>

      {/* Grille d'articles */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {articles.map((article) => (
          <article 
            key={article.id} 
            className="group bg-white rounded-3xl border border-slate-200 overflow-hidden hover:border-blue-300 hover:shadow-xl hover:shadow-blue-50 transition-all flex flex-col h-full"
          >
            {/* Image d'illustration */}
            <div className="aspect-video bg-slate-100 overflow-hidden relative">
              {article.thumbnail ? (
                <img 
                  src={article.thumbnail} 
                  alt={article.title} 
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
