import React, { useState, useEffect } from 'react';

interface Article {
  id: string;
  title: string;
  published: string;
  content: string;
  summary: string;
  link: string;
  author: string;
  image?: string;
}

const Actus: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    const fetchArticles = async () => {
      try {
        const blogUrl = 'https://bia-acp.blogspot.com/feeds/posts/default?alt=json';
        // Utilisation du proxy AllOrigins pour contourner le blocage CORS
        const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(blogUrl)}`;

        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error('Erreur réseau');

        const rawData = await response.json();
        const data = JSON.parse(rawData.contents);
        const entries = data.feed.entry || [];

        const parsed: Article[] = entries.map((entry: any) => {
          const contentStr = entry.content ? entry.content.$t : "";
          // Extraction de la première image de l'article
          const imgMatch = contentStr.match(/<img[^>]+src="([^">]+)"/);

          return {
            id: entry.id.$t,
            title: entry.title.$t,
            published: new Date(entry.published.$t).toLocaleDateString('fr-FR', {
              day: 'numeric',
              month: 'long',
              year: 'numeric'
            }),
            content: contentStr,
            summary: contentStr.replace(/<[^>]*>?/gm, '').substring(0, 160) + '...',
            link: entry.link.find((l: any) => l.rel === 'alternate')?.href || '#',
            author: entry.author[0].name.$t,
            image: imgMatch ? imgMatch[1] : null
          };
        });

        setArticles(parsed);
        setLoading(false);
      } catch (err) {
        console.error("Erreur de récupération des articles:", err);
        setError(true);
        setLoading(false);
      }
    };

    fetchArticles();
  }, []);

  if (loading) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-pulse">
        {[1, 2, 3].map(i => (
          <div key={i} className="bg-white rounded-3xl h-96 border border-slate-100 shadow-sm"></div>
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-white rounded-3xl p-12 text-center border border-slate-200">
        <i className="fa-solid fa-triangle-exclamation text-4xl text-amber-500 mb-4"></i>
        <h3 className="text-xl font-bold text-slate-800">Articles indisponibles</h3>
        <p className="text-slate-500 mt-2">Nous ne parvenons pas à charger les articles pour le moment.</p>
        <a href="https://bia-acp.blogspot.com/" target="_blank" className="mt-6 inline-block text-blue-600 font-bold underline">Voir sur Blogger</a>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {articles.map((art) => (
          <article key={art.id} className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group">
            {/* Image d'entête de l'article */}
            <div className="h-52 bg-slate-100 relative overflow-hidden">
              {art.image ? (
                <img src={art.image} alt="" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
              ) : (
                <div className="w-full h-full flex items-center justify-center bg-blue-50 text-blue-200">
                  <i className="fa-solid fa-newspaper text-6xl"></i>
                </div>
              )}
