  // Calcul du zoom intelligent
  const updateDefaultZoom = useCallback(() => {
    const isLandscape = window.innerWidth > window.innerHeight;
    const isMobile = window.innerWidth < 768;
    const isTablet = window.innerWidth >= 768 && window.innerWidth < 1024;

    if (isMobile) {
      setZoomScale(isLandscape ? 1.0 : 0.65);
    } else if (isTablet) {
      setZoomScale(isLandscape ? 1.15 : 0.85);
    } else {
      // Desktop
      setZoomScale(isLandscape ? 1.1 : 0.95);
    }
  }, []);

  useEffect(() => {
    updateDefaultZoom();
    window.addEventListener('resize', updateDefaultZoom);
    window.addEventListener('orientationchange', updateDefaultZoom);
    return () => {
      window.removeEventListener('resize', updateDefaultZoom);
      window.removeEventListener('orientationchange', updateDefaultZoom);
    };
  }, [updateDefaultZoom]);

  const handleRefresh = () => {
    window.location.reload();
