import React, { useState, useEffect, useCallback } from 'react';

interface Article {
  id: string;
  title: string;
  published: string;
  content: string;
  summary: string;
  link: string;
  author: string;
  image?: string;
}

const Actus: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState(false);

  const fetchArticles = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true);
    else setLoading(true);

    setError(false);

    try {
      // Stratégie AllOrigins + cache buster agressif + format json v2 de blogger
      const cacheBuster = `t=${Date.now()}`;
      const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json&${cacheBuster}`;
      const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(blogUrl)}`;

      const response = await fetch(proxyUrl);
      if (!response.ok) throw new Error('Proxy error');

      const rawData = await response.json();
      if (!rawData.contents) throw new Error('Empty response');

      const data = JSON.parse(rawData.contents);
      const entries = data.feed.entry || [];

      const parsed: Article[] = entries.map((entry: any) => {
        const contentStr = entry.content ? entry.content.$t : "";
        const imgMatch = contentStr.match(/<img[^>]+src="([^">]+)"/);

        return {
          id: entry.id.$t,
          title: entry.title.$t,
          published: new Date(entry.published.$t).toLocaleDateString('fr-FR', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
          }),
          content: contentStr,
          summary: contentStr.replace(/<[^>]*>?/gm, '').substring(0, 120).trim() + '...',
          link: entry.link.find((l: any) => l.rel === 'alternate')?.href || 'https://bia-acp.blogspot.com/',
          author: entry.author?.[0]?.name?.$t || 'Instructeur BIA',
          image: imgMatch ? imgMatch[1] : null
        };
      });

      setArticles(parsed);
      setError(parsed.length === 0);
    } catch (err) {
      console.error("Actus Fetch Error:", err);
      setError(true);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    fetchArticles();
  }, [fetchArticles]);

  if (loading && !refreshing) {
    return (
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-pulse">
        {[1, 2, 3].map(i => (
          <div key={i} className="bg-white rounded-3xl h-80 border border-slate-100"></div>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
        <div className="flex items-center">
          <div className={`w-2 h-2 rounded-full mr-3 ${refreshing ? 'bg-amber-400 animate-ping' : articles.length > 0 ? 'bg-green-500' : 'bg-red-500'}`}></div>
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
            {refreshing ? 'Synchronisation...' : articles.length > 0 ? 'Articles Synchronisés' : 'Échec Synchro'}
          </span>
        </div>
        <button 
          onClick={() => fetchArticles(true)}
          disabled={refreshing}
          className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-bold transition-all disabled:opacity-50 active:scale-95"
        >
          <i className={`fa-solid fa-arrows-rotate mr-2 ${refreshing ? 'fa-spin' : ''}`}></i>
          Rafraîchir
        </button>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-100 rounded-3xl p-10 text-center">
          <i className="fa-solid fa-triangle-exclamation text-red-400 text-4xl mb-4"></i>
          <h3 className="font-black text-red-900 mb-2">Impossible de charger les actus</h3>
          <p className="text-red-700 text-sm mb-6 max-w-sm mx-auto">Veuillez vérifier votre connexion internet ou réessayer dans quelques instants.</p>
          <button onClick={() => fetchArticles(true)} className="bg-red-600 text-white px-6 py-3 rounded-xl font-bold text-xs shadow-lg shadow-red-200">
            Réessayer maintenant
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 sm:gap-8">
        {articles.map((art) => (
          <article key={art.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl transition-all group flex flex-col">
            <div className="h-44 sm:h-52 bg-slate-100 relative overflow-hidden">
