interface Article {
  id: string;
  title: string;
  published: string;
  content: string;
  summary: string;
  link: string;
  author: string;
  image?: string;
}

const Actus: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState(false);

  const fetchArticles = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true);
    else setLoading(true);

    setError(false);

    try {
      // Utilisation d'un paramètre temporel unique pour bypasser le cache du proxy
      const timestamp = new Date().getTime();
      const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json&t=${timestamp}`;
      const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(blogUrl)}&timestamp=${timestamp}`;

      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 10000); // Timeout après 10s

      const response = await fetch(proxyUrl, { signal: controller.signal });
      clearTimeout(timeoutId);

      if (!response.ok) throw new Error('Proxy error');

      const rawData = await response.json();
      if (!rawData.contents) throw new Error('Empty content from proxy');

      const data = JSON.parse(rawData.contents);
      const entries = data.feed.entry || [];

      const parsed: Article[] = entries.map((entry: any) => {
        const contentStr = entry.content ? entry.content.$t : (entry.summary ? entry.summary.$t : "");
        // Extraction améliorée de l'image
        let imageUrl = null;
        const imgMatch = contentStr.match(/<img[^>]+src="([^">]+)"/);
        if (imgMatch) {
          imageUrl = imgMatch[1];
        } else if (entry.media$thumbnail) {
          imageUrl = entry.media$thumbnail.url.replace('s72-c', 's1600');
        }

        return {
          id: entry.id.$t,
          title: entry.title.$t,
          published: new Date(entry.published.$t).toLocaleDateString('fr-FR', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
          }),
          content: contentStr,
          summary: contentStr.replace(/<[^>]*>?/gm, '').substring(0, 120).trim() + '...',
          link: entry.link.find((l: any) => l.rel === 'alternate')?.href || 'https://bia-acp.blogspot.com/',
          author: entry.author?.[0]?.name?.$t || 'Instructeur BIA',
          image: imageUrl
        };
      });

      setArticles(parsed);
      setError(parsed.length === 0);
    } catch (err) {
      console.error("Actus Fetch Error:", err);
      setError(true);
      // Fallback : si on a déjà des articles en local, on ne les efface pas en cas d'erreur de refresh
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    fetchArticles();
  }, [fetchArticles]);

  if (loading && !refreshing) {
    return (
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-pulse">
