interface Article {
  id: string;
  title: string;
  published: string;
  content: string;
  summary: string;
  link: string;
  author: string;
  image?: string;
}

const Actus: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState(false);

  // Référence pour suivre le contrôleur d'abandon actuel
  const abortControllerRef = useRef<AbortController | null>(null);

  const fetchArticles = useCallback(async (isRefresh = false) => {
    // Annuler toute requête en cours avant d'en commencer une nouvelle
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    const controller = new AbortController();
    abortControllerRef.current = controller;

    if (isRefresh) setRefreshing(true);
    else setLoading(true);

    setError(false);

    try {
      const ts = new Date().getTime();
      const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json&t=${ts}`;
      const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(blogUrl)}&_ts=${ts}`;

      // Augmentation du timeout à 20s
      const timeoutId = setTimeout(() => controller.abort(), 20000); 

      const response = await fetch(proxyUrl, { 
        signal: controller.signal,
        headers: { 'Cache-Control': 'no-cache' }
      });

      clearTimeout(timeoutId);

      if (!response.ok) throw new Error(`Proxy status: ${response.status}`);

      const rawData = await response.json();
      if (!rawData.contents) throw new Error('Réponse vide du proxy');

      const data = JSON.parse(rawData.contents);
