        if (imgMatch) {
          imageUrl = imgMatch[1];
        } else if (entry.media$thumbnail) {
          imageUrl = entry.media$thumbnail.url.replace('s72-c', 's1600');
        }

        return {
          id: entry.id.$t,
          title: entry.title.$t,
          published: new Date(entry.published.$t).toLocaleDateString('fr-FR', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
          }),
          content: contentStr,
          summary: contentStr.replace(/<[^>]*>?/gm, '').substring(0, 150).trim() + '...',
          link: entry.link.find((l: any) => l.rel === 'alternate')?.href || 'https://bia-acp.blogspot.com/',
          author: entry.author?.[0]?.name?.$t || 'Instructeur BIA',
          image: imageUrl
        };
      });

      setArticles(parsed);
      setError(parsed.length === 0);
    } catch (err: any) {
      // Ignorer les erreurs causées par l'abandon intentionnel
      if (err.name === 'AbortError') {
        return;
      }
      console.error("Actus Fetch Error:", err);
      setError(true);
    } finally {
      // Ne mettre à jour les états que si cette requête est toujours la plus récente
      if (abortControllerRef.current === controller) {
        setLoading(false);
        setRefreshing(false);
      }
    }
