    fetchArticles();
    return () => {
      // Nettoyage : abandonner toute requête pendante lors du démontage
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [fetchArticles]);

  if (loading && !refreshing) {
    return (
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-pulse">
        {[1, 2, 3].map(i => (
          <div key={i} className="bg-white rounded-[2rem] h-80 border border-slate-100"></div>
        ))}
      </div>
    );
  }

