import React, { useState, useEffect, useCallback, useRef } from 'react';

interface Article {
  id: string;
  title: string;
  published: string;
  content: string;
  summary: string;
  link: string;
  author: string;
  image?: string;
}

const Actus: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState(false);

  const abortControllerRef = useRef<AbortController | null>(null);

  const fetchWithProxy = async (url: string, signal: AbortSignal) => {
    const ts = new Date().getTime();
    const encodedUrl = encodeURIComponent(`${url}${url.includes('?') ? '&' : '?'}_t=${ts}`);

    // Tentative 1: AllOrigins
    try {
      const proxyUrl = `https://api.allorigins.win/get?url=${encodedUrl}`;
      const response = await fetch(proxyUrl, { signal });
      if (response.ok) {
        const rawData = await response.json();
        if (rawData.contents) return JSON.parse(rawData.contents);
      }
    } catch (e) {
      if ((e as Error).name === 'AbortError') throw e;
      console.warn("AllOrigins failed, trying fallback proxy...");
    }

    // Tentative 2: CorsProxy.io (Fallback)
    try {
      const fallbackUrl = `https://corsproxy.io/?${url}${url.includes('?') ? '&' : '?'}_t=${ts}`;
      const response = await fetch(fallbackUrl, { signal });
      if (response.ok) return await response.json();
    } catch (e) {
      if ((e as Error).name === 'AbortError') throw e;
      throw new Error("Toutes les tentatives de proxy ont échoué");
    }

    throw new Error("Impossible de récupérer les données");
  };

  const fetchArticles = useCallback(async (isRefresh = false) => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    const controller = new AbortController();
    abortControllerRef.current = controller;

    if (isRefresh) setRefreshing(true);
    else setLoading(true);

    setError(false);

    try {
      const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json`;

      const timeoutId = setTimeout(() => controller.abort(), 25000); 
      const data = await fetchWithProxy(blogUrl, controller.signal);
      clearTimeout(timeoutId);

      const entries = data.feed.entry || [];

      const parsed: Article[] = entries.map((entry: any) => {
        const contentStr = entry.content ? entry.content.$t : (entry.summary ? entry.summary.$t : "");

        let imageUrl = null;
        const imgMatch = contentStr.match(/<img[^>]+src="([^">]+)"/);
        if (imgMatch) {
          imageUrl = imgMatch[1];
        } else if (entry.media$thumbnail) {
          imageUrl = entry.media$thumbnail.url.replace('s72-c', 's1600');
        }

        return {
          id: entry.id.$t,
          title: entry.title.$t,
          published: new Date(entry.published.$t).toLocaleDateString('fr-FR', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
          }),
          content: contentStr,
          summary: contentStr.replace(/<[^>]*>?/gm, '').substring(0, 150).trim() + '...',
          link: entry.link.find((l: any) => l.rel === 'alternate')?.href || 'https://bia-acp.blogspot.com/',
          author: entry.author?.[0]?.name?.$t || 'Instructeur BIA',
          image: imageUrl
        };
      });

      setArticles(parsed);
      setError(parsed.length === 0);
    } catch (err: any) {
      if (err.name === 'AbortError') return;
      console.error("Actus Fetch Error:", err.message || err);
      setError(true);
    } finally {
      if (abortControllerRef.current === controller) {
        setLoading(false);
        setRefreshing(false);
      }
    }
  }, []);

  useEffect(() => {
    fetchArticles();
    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [fetchArticles]);

  if (loading && !refreshing) {
    return (
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-pulse">
        {[1, 2, 3].map(i => (
          <div key={i} className="bg-white rounded-[2rem] h-80 border border-slate-100 shadow-sm"></div>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
        <div className="flex items-center">
          <div className={`w-2.5 h-2.5 rounded-full mr-3 ${refreshing ? 'bg-amber-400 animate-pulse' : articles.length > 0 ? 'bg-green-500' : 'bg-red-500'}`}></div>
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
            {refreshing ? 'Synchronisation...' : articles.length > 0 ? 'Articles en ligne' : 'Connexion interrompue'}
          </span>
        </div>
        <button 
          onClick={() => fetchArticles(true)}
          disabled={refreshing}
          className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-bold transition-all disabled:opacity-50 active:scale-95 flex items-center"
        >
          <i className={`fa-solid fa-arrows-rotate mr-2 ${refreshing ? 'fa-spin' : ''}`}></i>
          {refreshing ? 'Patientez...' : 'Actualiser'}
        </button>
      </div>

      {error && articles.length === 0 && (
        <div className="bg-white border border-slate-200 rounded-3xl p-10 text-center shadow-sm">
          <div className="w-20 h-20 bg-red-50 text-red-400 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">
            <i className="fa-solid fa-cloud-bolt"></i>
          </div>
          <h3 className="font-black text-slate-900 mb-2">Erreur de chargement</h3>
          <p className="text-slate-500 text-sm mb-8 max-w-sm mx-auto">
            Les serveurs Blogger ou nos proxys de connexion sont temporairement indisponibles.
          </p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            <button onClick={() => fetchArticles(true)} className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold text-xs shadow-lg hover:bg-blue-700 transition-colors">
              Réessayer
            </button>
            <a href="https://bia-acp.blogspot.com/" target="_blank" rel="noopener noreferrer" className="bg-slate-100 text-slate-700 px-8 py-3 rounded-xl font-bold text-xs hover:bg-slate-200 transition-colors">
              Voir sur Blogger
            </a>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 sm:gap-8">
        {articles.map((art) => (
          <article key={art.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl transition-all group flex flex-col h-full">
            <div className="h-44 sm:h-52 bg-slate-100 relative overflow-hidden">
              {art.image ? (
                <img src={art.image} alt="" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
              ) : (
                <div className="w-full h-full flex items-center justify-center bg-blue-50 text-blue-200">
                  <i className="fa-solid fa-plane text-5xl rotate-12"></i>
                </div>
              )}
              <div className="absolute top-4 left-4">
                <span className="px-3 py-1 bg-white/90 backdrop-blur shadow-sm rounded-full text-[9px] font-black text-slate-800 uppercase tracking-widest">
                  {art.published}
                </span>
              </div>
            </div>

            <div className="p-6 sm:p-8 flex flex-col flex-1">
              <h3 className="text-lg font-black text-slate-900 leading-tight mb-4 group-hover:text-blue-600 transition-colors line-clamp-2">
                {art.title}
              </h3>
              <p className="text-slate-500 text-xs sm:text-sm leading-relaxed mb-6 line-clamp-3 italic">
                {art.summary}
              </p>

              <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest truncate max-w-[140px]">
                  <i className="fa-solid fa-circle-user mr-1.5 text-blue-500"></i>
                  {art.author}
                </span>
                <a 
                  href={art.link} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="w-10 h-10 bg-blue-600 text-white rounded-xl flex items-center justify-center hover:bg-slate-900 transition-all shadow-md active:scale-90"
                >
                  <i className="fa-solid fa-arrow-right text-sm"></i>
                </a>
              </div>
            </div>
          </article>
        ))}
      </div>
    </div>
  );
};

export default Actus;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';

interface Article {
  id: string;
  title: string;
  published: string;
  publishedRaw: number; // Pour le tri
  content: string;
  summary: string;
  link: string;
  author: string;
  image?: string;
}

const CACHE_KEY = 'bia_actus_cache';
const CACHE_EXPIRY = 30 * 60 * 1000; // 30 minutes
const ITEMS_PER_PAGE = 6;

const Actus: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [displayCount, setDisplayCount] = useState(ITEMS_PER_PAGE);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState(false);

  const abortControllerRef = useRef<AbortController | null>(null);

  // Chargement du cache au montage
  useEffect(() => {
    const cached = localStorage.getItem(CACHE_KEY);
    if (cached) {
      try {
        const { timestamp, data } = JSON.parse(cached);
        if (Date.now() - timestamp < CACHE_EXPIRY) {
          setArticles(data);
          setLoading(false);
          // On rafraîchit quand même en arrière-plan si le cache a plus de 5 min
          if (Date.now() - timestamp > 5 * 60 * 1000) {
            fetchArticles(true);
          }
          return;
        }
      } catch (e) {
        console.error("Cache parsing error", e);
      }
    }
    fetchArticles();
  }, []);

  const fetchWithProxy = async (url: string, signal: AbortSignal) => {
    const ts = new Date().getTime();
    const encodedUrl = encodeURIComponent(`${url}${url.includes('?') ? '&' : '?'}_t=${ts}`);

    // Tentative 1: AllOrigins
    try {
      const proxyUrl = `https://api.allorigins.win/get?url=${encodedUrl}`;
      const response = await fetch(proxyUrl, { signal });
      if (response.ok) {
        const rawData = await response.json();
        if (rawData.contents) return JSON.parse(rawData.contents);
      }
    } catch (e) {
      if ((e as Error).name === 'AbortError') throw e;
      console.warn("AllOrigins failed, trying fallback proxy...");
    }

    // Tentative 2: CorsProxy.io (Fallback)
    try {
      const fallbackUrl = `https://corsproxy.io/?${url}${url.includes('?') ? '&' : '?'}_t=${ts}`;
      const response = await fetch(fallbackUrl, { signal });
      if (response.ok) return await response.json();
    } catch (e) {
      if ((e as Error).name === 'AbortError') throw e;
      throw new Error("Toutes les tentatives de proxy ont échoué");
    }

    throw new Error("Impossible de récupérer les données");
  };

  const fetchArticles = useCallback(async (isRefresh = false) => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    const controller = new AbortController();
    abortControllerRef.current = controller;

    if (isRefresh) setRefreshing(true);
    else setLoading(true);

    setError(false);

    try {
      const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json`;

      const timeoutId = setTimeout(() => controller.abort(), 25000); 
      const data = await fetchWithProxy(blogUrl, controller.signal);
      clearTimeout(timeoutId);

      const entries = data.feed.entry || [];

      const parsed: Article[] = entries.map((entry: any) => {
        const contentStr = entry.content ? entry.content.$t : (entry.summary ? entry.summary.$t : "");
        const pubDate = new Date(entry.published.$t);

        let imageUrl = null;
        const imgMatch = contentStr.match(/<img[^>]+src="([^">]+)"/);
        if (imgMatch) {
          imageUrl = imgMatch[1];
        } else if (entry.media$thumbnail) {
          imageUrl = entry.media$thumbnail.url.replace('s72-c', 's1600');
        }

        return {
          id: entry.id.$t,
          title: entry.title.$t,
          publishedRaw: pubDate.getTime(),
          published: pubDate.toLocaleDateString('fr-FR', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
          }),
          content: contentStr,
          summary: contentStr.replace(/<[^>]*>?/gm, '').substring(0, 150).trim() + '...',
          link: entry.link.find((l: any) => l.rel === 'alternate')?.href || 'https://bia-acp.blogspot.com/',
          author: entry.author?.[0]?.name?.$t || 'Instructeur BIA',
          image: imageUrl
        };
      });

      // Tri par date décroissante
      parsed.sort((a, b) => b.publishedRaw - a.publishedRaw);

      setArticles(parsed);

      // Mise en cache
      localStorage.setItem(CACHE_KEY, JSON.stringify({
        timestamp: Date.now(),
        data: parsed
      }));

      setError(parsed.length === 0);
    } catch (err: any) {
      if (err.name === 'AbortError') return;
      console.error("Actus Fetch Error:", err.message || err);
      // Si on a déjà des articles (du cache), on n'affiche pas l'erreur bloquante
      if (articles.length === 0) setError(true);
    } finally {
      if (abortControllerRef.current === controller) {
        setLoading(false);
        setRefreshing(false);
      }
    }
  }, [articles.length]);

  const displayedArticles = useMemo(() => {
    return articles.slice(0, displayCount);
  }, [articles, displayCount]);

  const handleLoadMore = () => {
    setDisplayCount(prev => prev + ITEMS_PER_PAGE);
  };

  if (loading && articles.length === 0) {
    return (
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-pulse">
        {[1, 2, 3, 4, 5, 6].map(i => (
          <div key={i} className="bg-white rounded-[2rem] h-96 border border-slate-100 shadow-sm overflow-hidden">
             <div className="h-44 bg-slate-100"></div>
             <div className="p-6 space-y-4">
               <div className="h-6 bg-slate-100 rounded w-3/4"></div>
               <div className="h-4 bg-slate-100 rounded w-full"></div>
               <div className="h-4 bg-slate-100 rounded w-5/6"></div>
             </div>
          </div>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between bg-white p-4 rounded-2xl border border-slate-200 shadow-sm gap-4">
        <div className="flex items-center">
          <div className={`w-2.5 h-2.5 rounded-full mr-3 ${refreshing ? 'bg-amber-400 animate-pulse' : articles.length > 0 ? 'bg-green-500' : 'bg-red-500'}`}></div>
          <div>
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">
              {refreshing ? 'Synchronisation...' : articles.length > 0 ? 'Articles à jour' : 'Connexion interrompue'}
            </span>
            {articles.length > 0 && !refreshing && (
              <span className="text-[8px] text-slate-400 font-bold uppercase">
                {articles.length} publications au total
              </span>
            )}
          </div>
        </div>
        <button 
          onClick={() => fetchArticles(true)}
          disabled={refreshing}
          className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-bold transition-all disabled:opacity-50 active:scale-95 flex items-center justify-center"
        >
          <i className={`fa-solid fa-arrows-rotate mr-2 ${refreshing ? 'fa-spin' : ''}`}></i>
          {refreshing ? 'Mise à jour...' : 'Forcer l\'actualisation'}
        </button>
      </div>

      {error && articles.length === 0 && (
        <div className="bg-white border border-slate-200 rounded-3xl p-10 text-center shadow-sm">
          <div className="w-20 h-20 bg-red-50 text-red-400 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">
            <i className="fa-solid fa-cloud-bolt"></i>
          </div>
          <h3 className="font-black text-slate-900 mb-2">Erreur de chargement</h3>
          <p className="text-slate-500 text-sm mb-8 max-w-sm mx-auto">
            Impossible de récupérer les actualités. Vérifiez votre connexion.
          </p>
          <button onClick={() => fetchArticles(true)} className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold text-xs shadow-lg hover:bg-blue-700 transition-colors">
            Réessayer
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 sm:gap-8">
        {displayedArticles.map((art) => (
          <article key={art.id} className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 group flex flex-col h-full">
            <div className="h-44 sm:h-52 bg-slate-100 relative overflow-hidden">
              {art.image ? (
                <img 
                  src={art.image} 
                  alt="" 
                  loading="lazy"
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" 
                />
              ) : (
                <div className="w-full h-full flex items-center justify-center bg-blue-50 text-blue-200">
                  <i className="fa-solid fa-plane text-5xl rotate-12"></i>
                </div>
              )}
              <div className="absolute top-4 left-4">
                <span className="px-3 py-1 bg-white/90 backdrop-blur shadow-sm rounded-full text-[9px] font-black text-slate-800 uppercase tracking-widest">
                  {art.published}
                </span>
              </div>
            </div>

            <div className="p-6 sm:p-8 flex flex-col flex-1">
              <h3 className="text-lg font-black text-slate-900 leading-tight mb-4 group-hover:text-blue-600 transition-colors line-clamp-2">
                {art.title}
              </h3>
              <p className="text-slate-500 text-xs sm:text-sm leading-relaxed mb-6 line-clamp-3 italic">
                {art.summary}
              </p>

              <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest truncate max-w-[140px]">
                  <i className="fa-solid fa-circle-user mr-1.5 text-blue-500"></i>
                  {art.author}
                </span>
                <a 
                  href={art.link} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="w-10 h-10 bg-blue-600 text-white rounded-xl flex items-center justify-center hover:bg-slate-900 transition-all shadow-md active:scale-90"
                >
                  <i className="fa-solid fa-arrow-right text-sm"></i>
                </a>
              </div>
            </div>
          </article>
        ))}
      </div>

      {displayCount < articles.length && (
        <div className="flex justify-center pt-8 pb-4">
          <button 
            onClick={handleLoadMore}
            className="px-10 py-4 bg-white border border-slate-200 text-slate-900 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-slate-50 hover:border-blue-300 transition-all shadow-sm active:scale-95"
          >
            Charger plus d'articles
            <i className="fa-solid fa-chevron-down ml-3 text-blue-500"></i>
          </button>
        </div>
      )}
    </div>
  );
};

export default Actus;

