  const publicUrl = "https://docs.google.com/spreadsheets/d/e/2PACX-1vRBOaU_OuHjCh4GQLjyjDNOsoBZgWDhmt_EJf_LQuihoSVnEQusw1PKTxM70PkzCwzIgk4mmjWo58BZ/pubhtml";

  // Calcul du zoom intelligent pour occuper la largeur
  const updateDefaultZoom = useCallback(() => {
    const width = window.innerWidth;
    const height = window.innerHeight;
    const isLandscape = width > height;

    if (width < 480) {
      setZoomScale(isLandscape ? 0.9 : 0.55);
    } else if (width < 768) {
      setZoomScale(isLandscape ? 1.0 : 0.75);
    } else if (width < 1024) {
      setZoomScale(1.0);
    } else if (width < 1440) {
      setZoomScale(1.1);
    } else {
      setZoomScale(1.25);
    }
  }, []);

  useEffect(() => {
    updateDefaultZoom();
    const handleResize = () => updateDefaultZoom();

    window.addEventListener('resize', handleResize);
    window.addEventListener('orientationchange', handleResize);

    if (window.visualViewport) {
      window.visualViewport.addEventListener('resize', handleResize);
    }

    return () => {
      window.removeEventListener('resize', handleResize);
      window.removeEventListener('orientationchange', handleResize);
      if (window.visualViewport) {
        window.visualViewport.removeEventListener('resize', handleResize);
      }
    };
  }, [updateDefaultZoom]);

  const handleRefresh = () => {
    window.location.reload();
  };

  const adjustZoom = (delta: number) => {
    setZoomScale(prev => Math.max(0.3, Math.min(2.5, prev + delta)));
  };

  return (
