          </div>
        </div>

        <div className="bg-amber-50 border border-amber-200 rounded-2xl sm:rounded-3xl p-4 sm:p-8 flex items-center md:flex-col md:justify-center md:items-start">
          <div className="w-8 h-8 bg-amber-100 text-amber-600 rounded-lg flex items-center justify-center text-sm mr-3 md:mr-0 md:mb-2 shrink-0">
            <i className="fa-solid fa-triangle-exclamation"></i>
          </div>
          <p className="text-[11px] sm:text-sm text-amber-800 font-semibold leading-snug">
            Sauf vacances scolaires ou avis contraire.
          </p>
        </div>
      </div>

      {/* Barre d'outils */}
      <div className="bg-white p-3 sm:p-4 rounded-2xl border border-slate-200 flex flex-wrap justify-between items-center gap-3 shadow-sm relative z-30">
        <div className="flex items-center bg-slate-100 rounded-xl p-1 border border-slate-200 flex-1 sm:flex-none justify-between">
          <button 
            onClick={() => adjustZoom(-0.1)}
            className="w-9 h-9 flex items-center justify-center text-slate-600 hover:bg-white hover:text-blue-600 rounded-lg transition-all active:scale-90"
            title="Dézoomer"
          >
            <i className="fa-solid fa-magnifying-glass-minus"></i>
          </button>
          <div className="px-3 flex flex-col items-center min-w-[60px]">
            <span className="text-[10px] font-black text-slate-500 leading-none">
              {Math.round(zoomScale * 100)}%
            </span>
            <span className="text-[7px] font-bold text-slate-400 uppercase mt-0.5">Zoom</span>
          </div>
          <button 
            onClick={() => adjustZoom(0.1)}
            className="w-9 h-9 flex items-center justify-center text-slate-600 hover:bg-white hover:text-blue-600 rounded-lg transition-all active:scale-90"
            title="Zoomer"
          >
            <i className="fa-solid fa-magnifying-glass-plus"></i>
          </button>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
          <button 
            onClick={handleRefresh}
            className="flex-1 sm:flex-none flex items-center justify-center px-4 py-2 sm:py-3 bg-slate-50 text-slate-700 rounded-xl text-[10px] sm:text-xs font-bold transition-all border border-slate-200 hover:bg-slate-100"
