        <div className="text-blue-900 text-[11px] sm:text-sm leading-relaxed text-justify">
          <p className="mb-2 font-medium">
            Le planning ci-dessus est mis à jour en temps réel par les instructeurs.
          </p>
          <p className="font-medium">
            En cas de problème d'affichage sur mobile, utilisez le bouton <strong>Plein écran</strong>.
          </p>
        </div>
      </div>
    </div>
  );
};

