            <p className="text-blue-300 text-sm sm:text-lg font-medium">
              <span className="text-white font-black">09:00 — 11:00</span> • Aéroclub du Poitou
            </p>
          </div>
        </div>

        <div className="bg-amber-50 border-2 border-amber-200/50 rounded-3xl p-6 flex flex-col justify-center">
          <div className="flex items-center gap-3 mb-2">
            <i className="fa-solid fa-triangle-exclamation text-amber-500"></i>
            <span className="text-[10px] font-black text-amber-600 uppercase tracking-widest">Important</span>
          </div>
          <p className="text-xs sm:text-sm text-amber-900 font-bold leading-tight">
            Vérifiez toujours le planning le vendredi soir pour d'éventuels changements.
          </p>
        </div>
      </div>

      {/* Toolbar épurée */}
      <div className="flex flex-wrap items-center justify-between gap-4 bg-white p-3 rounded-2xl border border-slate-200 shadow-sm">
        <div className="flex items-center gap-1 bg-slate-50 p-1 rounded-xl border border-slate-100">
          <button 
            onClick={() => adjustZoom(-0.1)}
            className="w-10 h-10 flex items-center justify-center text-slate-500 hover:bg-white hover:text-blue-600 rounded-lg transition-all shadow-sm active:scale-90"
          >
            <i className="fa-solid fa-magnifying-glass-minus"></i>
          </button>
          <div className="px-4 text-[10px] font-black text-slate-400 uppercase tracking-widest min-w-[70px] text-center">
            {Math.round(zoomScale * 100)}%
          </div>
          <button 
            onClick={() => adjustZoom(0.1)}
            className="w-10 h-10 flex items-center justify-center text-slate-500 hover:bg-white hover:text-blue-600 rounded-lg transition-all shadow-sm active:scale-90"
          >
            <i className="fa-solid fa-magnifying-glass-plus"></i>
          </button>
        </div>

        <div className="flex gap-2">
           <button 
             onClick={() => window.location.reload()}
