      {/* Container de l'Iframe SANS bandes noires et SANS scroll externe */}
      <div className="bg-white rounded-[2rem] border-2 border-slate-200 overflow-hidden shadow-2xl h-[65vh] sm:h-[75vh] min-h-[450px] relative">
