  // Calcule le zoom pour que le tableau occupe toute la largeur
  const updateDefaultZoom = useCallback(() => {
    if (containerRef.current) {
      const containerWidth = containerRef.current.offsetWidth;
      // 960px est une largeur de référence pour laquelle le tableau Google est lisible sans zoom
      const baseSheetWidth = 960; 
      const calculatedScale = containerWidth / baseSheetWidth;

      // On bride le zoom auto entre 0.4 et 1.5 pour garder une lisibilité
      setZoomScale(Math.max(0.4, Math.min(1.5, calculatedScale)));
    }
  }, []);

  useEffect(() => {
    // Petit délai pour s'assurer que le DOM est prêt
    const timer = setTimeout(updateDefaultZoom, 150);
    window.addEventListener('resize', updateDefaultZoom);
    window.addEventListener('orientationchange', updateDefaultZoom);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', updateDefaultZoom);
      window.removeEventListener('orientationchange', updateDefaultZoom);
