          summary: contentStr.replace(/<[^>]*>?/gm, '').substring(0, 150).trim() + '...',
          link: entry.link.find((l: any) => l.rel === 'alternate')?.href || '',
          author: entry.author?.[0]?.name?.$t || 'Instructeur BIA',
          image: imageUrl
