  const [refreshing, setRefreshing] = useState(false);
  const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
  const [fetchError, setFetchError] = useState(false);

  const fetchArticles = async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true); else setLoading(true);
    setFetchError(false);

    const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json`;
    const proxies = [
      (url: string) => `https://api.allorigins.win/get?url=${encodeURIComponent(url + '&_t=' + Date.now())}`,
      (url: string) => `https://corsproxy.io/?${encodeURIComponent(url + '&_t=' + Date.now())}`
    ];

    let success = false;
    for (const getProxyUrl of proxies) {
      try {
        const response = await fetch(getProxyUrl(blogUrl));
        if (!response.ok) throw new Error("Proxy Error");

        const raw = await response.json();
        // AllOrigins encapsule dans .contents, CorsProxy non.
        const contentStr = raw.contents || JSON.stringify(raw);
        const data = JSON.parse(contentStr);

        const entries = data.feed.entry || [];
        const parsed: Article[] = entries.map((entry: any) => {
          const body = entry.content?.$t || entry.summary?.$t || "";
          const pubDate = new Date(entry.published.$t);
          let imageUrl = null;
          const imgMatch = body.match(/<img[^>]+src="([^">]+)"/);
          if (imgMatch) imageUrl = imgMatch[1];
          else if (entry.media$thumbnail) imageUrl = entry.media$thumbnail.url.replace('s72-c', 's1600');

          return {
            id: entry.id.$t,
            title: entry.title.$t,
            publishedRaw: pubDate.getTime(),
            published: pubDate.toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', year: 'numeric' }),
            content: body,
            summary: body.replace(/<[^>]*>?/gm, '').substring(0, 120).trim() + '...',
            image: imageUrl
          };
        });

        parsed.sort((a, b) => b.publishedRaw - a.publishedRaw);
        setArticles(parsed);
        success = true;
        break;
      } catch (e) {
        console.warn("Proxy failed, trying next...");
      }
    }

    if (!success) setFetchError(true);
    setLoading(false);
    setRefreshing(false);
  };

  useEffect(() => { fetchArticles(); }, []);

  if (selectedArticle) {
    return (
      <div className="animate-fade-in space-y-6 max-w-4xl mx-auto pb-10">
        <button onClick={() => setSelectedArticle(null)} className="flex items-center gap-2 px-5 py-2.5 bg-white border border-slate-200 text-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-sm">
