const Actus = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
  const [fetchError, setFetchError] = useState(false);

  const fetchArticles = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true); else setLoading(true);
    setFetchError(false);

    const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json`;
    const proxies = [
      (url: string) => `https://api.allorigins.win/get?url=${encodeURIComponent(url + '&_t=' + Date.now())}`,
      (url: string) => `https://corsproxy.io/?${encodeURIComponent(url + '&_t=' + Date.now())}`
    ];

    let success = false;
    for (const getProxyUrl of proxies) {
      try {
        const response = await fetch(getProxyUrl(blogUrl));
        if (!response.ok) throw new Error("Proxy response failed");

        const raw = await response.json();
        // AllOrigins encapsule dans .contents, CorsProxy non.
        let data;
        if (raw.contents) {
          data = JSON.parse(raw.contents);
        } else {
          data = raw;
        }

        const entries = data.feed.entry || [];
        const parsed: Article[] = entries.map((entry: any) => {
          const body = entry.content?.$t || entry.summary?.$t || "";
          const pubDate = new Date(entry.published.$t);
          let imageUrl = null;
          const imgMatch = body.match(/<img[^>]+src="([^">]+)"/);
          if (imgMatch) imageUrl = imgMatch[1];
          else if (entry.media$thumbnail) imageUrl = entry.media$thumbnail.url.replace('s72-c', 's1600');

          return {
            id: entry.id.$t,
            title: entry.title.$t,
            publishedRaw: pubDate.getTime(),
            published: pubDate.toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', year: 'numeric' }),
            content: body,
            summary: body.replace(/<[^>]*>?/gm, '').substring(0, 120).trim() + '...',
            image: imageUrl
          };
        });

        parsed.sort((a, b) => b.publishedRaw - a.publishedRaw);
        setArticles(parsed);
        success = true;
        break;
      } catch (e) {
        console.warn("Échec du proxy, tentative suivante...", e);
      }
    }

    if (!success) setFetchError(true);
    setLoading(false);
    setRefreshing(false);
  }, []);

  useEffect(() => { fetchArticles(); }, [fetchArticles]);

  if (selectedArticle) {
    return (
      <div className="animate-fade-in space-y-6 max-w-4xl mx-auto pb-10">
        <button onClick={() => setSelectedArticle(null)} className="flex items-center gap-2 px-5 py-2.5 bg-white border border-slate-200 text-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-sm">
          <i className="fa-solid fa-arrow-left"></i> Retour
        </button>
        <article className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-lg">
          {selectedArticle.image && <img src={selectedArticle.image} className="w-full h-64 sm:h-96 object-cover" />}
          <div className="p-8">
            <span className="px-3 py-1 bg-blue-50 text-[10px] font-black text-blue-600 uppercase rounded-full mb-4 inline-block">{selectedArticle.published}</span>
            <h2 className="text-2xl sm:text-3xl font-black text-slate-900 mb-6">{selectedArticle.title}</h2>
            <div className="prose prose-slate max-w-none text-slate-700 leading-relaxed space-y-4" dangerouslySetInnerHTML={{ __html: selectedArticle.content }} />
          </div>
        </article>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
        <div className="flex items-center text-[10px] font-black text-slate-500 uppercase tracking-widest">
          <div className={`w-2.5 h-2.5 rounded-full mr-3 ${refreshing ? 'bg-amber-400 animate-pulse' : (fetchError ? 'bg-red-500' : 'bg-green-500')}`}></div>
          {refreshing ? 'Sync...' : (fetchError ? 'Erreur Réseau' : 'Articles à jour')}
        </div>
        <button onClick={() => fetchArticles(true)} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-bold">Actualiser</button>
      </div>

      {loading && !refreshing ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1,2,3].map(i => <div key={i} className="bg-white h-80 rounded-3xl border border-slate-200 animate-pulse"></div>)}
        </div>
      ) : fetchError && articles.length === 0 ? (
        <div className="bg-red-50 border border-red-100 rounded-3xl p-10 text-center">
            <i className="fa-solid fa-cloud-slash text-red-300 text-4xl mb-4"></i>
            <p className="text-red-900 font-bold">Impossible de charger les actualités.</p>
            <p className="text-red-600 text-xs mt-2">Vérifiez votre connexion internet.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {articles.map((art) => (
            <article key={art.id} onClick={() => setSelectedArticle(art)} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl transition-all cursor-pointer flex flex-col group">
              <div className="h-44 bg-slate-100 relative overflow-hidden">
                {art.image && <img src={art.image} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" alt="" />}
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-[9px] font-black text-slate-800 uppercase tracking-widest">{art.published}</div>
              </div>
              <div className="p-6 flex flex-col flex-1">
                <h3 className="text-lg font-black text-slate-900 leading-tight mb-4 line-clamp-2">{art.title}</h3>
                <p className="text-slate-500 text-xs italic line-clamp-3 mb-6">{art.summary}</p>
                <div className="mt-auto flex justify-end"><i className="fa-solid fa-arrow-right text-blue-600 group-hover:translate-x-1 transition-transform"></i></div>
              </div>
            </article>
          ))}
        </div>
      )}
    </div>
  );
};

