  const fetchArt = useCallback(async () => {
    const blogUrl = `https://bia-acp.blogspot.com/feeds/posts/default?alt=json`;
    const proxies = [
      (url: string) => `https://api.allorigins.win/get?url=${encodeURIComponent(url + '&_t=' + Date.now())}`,
      (url: string) => `https://corsproxy.io/?${encodeURIComponent(url)}`
    ];

    for (const getProxyUrl of proxies) {
      try {
        const res = await fetch(getProxyUrl(blogUrl));
        if (!res.ok) continue;
        const raw = await res.json();
        const contentStr = typeof raw.contents === 'string' ? JSON.parse(raw.contents) : raw;
        const data = contentStr.feed ? contentStr : JSON.parse(raw.contents); // AllOrigins wrappe dans .contents

        const entries = data.feed.entry || [];
        const parsed = entries.map((e: any) => {
          const body = e.content?.$t || e.summary?.$t || "";
          const img = body.match(/<img[^>]+src="([^">]+)"/)?.[1] || e.media$thumbnail?.url.replace('s72-c', 's1600');
          return {
            id: e.id.$t, title: e.title.$t, 
            published: new Date(e.published.$t).toLocaleDateString('fr-FR', {day:'numeric', month:'short'}),
            content: body, image: img,
            summary: body.replace(/<[^>]*>?/gm, '').substring(0, 100) + '...'
          };
        });
        setArticles(parsed);
        setLoading(false);
        setError(false);
        return; // Success
